const body = $input.item.json.body || {};
const qid  = String(body.quote_id || '').trim();
// UUID format check (v4-ish): 8-4-4-4-12 hex with dashes
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(qid)) {
  return { json: { ok: false, status: 400, error: 'Invalid quote_id format' } };
}
return { json: { quote_id: qid } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Fetch Quote');
if (rows.length === 0) {
  return { json: { ok: false, status: 404, error: 'Quote not found' } };
}
const q = rows[0];
const now = new Date().toISOString();
// If still 'open' or 'sent', mark as 'viewed' on this fetch. Idempotent via PATCH only on those statuses.
const shouldMarkViewed = q.status === 'open' || q.status === 'sent';
return { json: {
  quote: q,
  should_mark_viewed: shouldMarkViewed,
  now: now
} };

// Final shape — strip the email + phone if you want to be extra-careful
// about exposing PII on a public endpoint. For V1 we return them since
// the customer already knows their own email (it was sent to them).
const q = $('Inspect Quote').first().json.quote;
const tpl = q.quote_templates || {};
const now = new Date().toISOString();
// If we just marked viewed, reflect it in the response.
const markedViewed = $('Inspect Quote').first().json.should_mark_viewed === true;
if (markedViewed && q.status === 'open' || q.status === 'sent') {
  q.status = 'viewed';
  q.viewed_at = now;
}
const expired = q.expires_at && new Date(q.expires_at).getTime() < Date.now();
return { json: {
  ok: true,
  quote: {
    id:                     q.id,
    industry_name:          tpl.industry_name || q.industry_slug,
    industry_emoji:         tpl.emoji || null,
    industry_description:   tpl.description || null,
    email:                  q.email,
    full_name:              q.full_name,
    company:                q.company,
    rules_applied:          q.rules_applied || [],
    addons_selected:        q.addons_selected || [],
    base_tier:              q.base_tier,
    base_monthly_cents:     q.base_monthly_cents,
    total_monthly_cents:    q.total_monthly_cents,
    total_one_time_cents:   q.total_one_time_cents,
    total_first_year_cents: q.total_first_year_cents,
    status:                 expired ? 'expired' : q.status,
    expires_at:             q.expires_at,
    expired:                expired,
    accepted_at:            q.accepted_at,
    declined_at:            q.declined_at,
    created_at:             q.created_at
  }
} };
